// Hand-edited (was: generated by CLI Printing Press). Reason: SEC's
// company_tickers.json doesn't accept a ?ticker query param — we have to
// fetch the full file and filter locally, populating edgar_companies on the
// way.

package cli

import (
	"encoding/json"
	"fmt"
	"strings"

	"github.com/mvanhorn/printing-press-library/library/other/edgar/internal/store"
	"github.com/spf13/cobra"
)

func newCompaniesLookupCmd(flags *rootFlags) *cobra.Command {
	var flagTicker string

	cmd := &cobra.Command{
		Use:     "lookup",
		Short:   "Resolve ticker → CIK (and name + SIC) from SEC's company_tickers.json. Cache 24h in local SQLite.",
		Example: "  edgar-pp-cli companies lookup --ticker AAPL",
		Annotations: map[string]string{
			"pp:endpoint":   "companies.lookup",
			"pp:method":     "GET",
			"pp:path":       "https://www.sec.gov/files/company_tickers.json",
			"mcp:read-only": "true",
		},
		RunE: func(cmd *cobra.Command, args []string) error {
			if dryRunOK(flags) {
				return nil
			}
			c, err := flags.newClient()
			if err != nil {
				return err
			}
			db, err := store.OpenWithContext(cmd.Context(), edgarDBPath())
			if err != nil {
				return fmt.Errorf("opening local store: %w", err)
			}
			defer db.Close()
			if err := db.EnsureEdgarSchema(cmd.Context()); err != nil {
				return err
			}

			// Refresh cache (24h TTL handled at lookup time, but refresh is cheap-ish)
			if err := refreshTickerCache(cmd.Context(), c, db); err != nil {
				return classifyAPIError(err, flags)
			}

			if flagTicker != "" {
				rec, lerr := db.LookupEdgarCompanyByTicker(cmd.Context(), flagTicker)
				if lerr != nil {
					return notFoundErr(fmt.Errorf("ticker %q not found", flagTicker))
				}
				return emitJSON(cmd, flags, rec)
			}

			// No filter: emit all rows. (May be ~10K entries; agents typically
			// pass --ticker so this is just for exploration.)
			rows, err := db.Query(`SELECT cik, ticker, name, COALESCE(sic,''), cached_at FROM edgar_companies ORDER BY ticker LIMIT 50`)
			if err != nil {
				return err
			}
			defer rows.Close()
			var all []store.EdgarCompany
			for rows.Next() {
				var r store.EdgarCompany
				if err := rows.Scan(&r.CIK, &r.Ticker, &r.Name, &r.SIC, &r.CachedAt); err != nil {
					return err
				}
				all = append(all, r)
			}
			return emitJSON(cmd, flags, all)
		},
	}
	cmd.Flags().StringVar(&flagTicker, "ticker", "", "Stock ticker (case-insensitive). Filters the response locally after fetching the SEC index.")

	_ = strings.ToUpper // keep import stable
	_ = json.Marshal
	return cmd
}
